1	// claim-office.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { quote } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office - quote", () => {
6	  // Empty / processing fee
7	  it("empty item list yields premium 5 G (only processing fee)", () => {
8	    expect(quote({ items: [], customer: { yearsInsured: 0, previousQuotes: 0 } })).toBe(5);
9	  });
10	
11	  // Single main item base premiums
12	  it.todo("single plain sword (newcomer, first insurance) yields 115 G (100 base + 10 first + 5 fee)");
13	  it.todo("single plain amulet (newcomer, first insurance) yields 71 G (60 base + 6 first + 5 fee)");
14	  it.todo("single plain staff (newcomer, first insurance) yields 93 G (80 base + 8 first + 5 fee)");
15	  it.todo("single plain potion (newcomer, first insurance) yields 49 G (40 base + 4 first + 5 fee)");
16	
17	  // Components - building block rule
18	  it.todo("2 runes yields base premium 50 G (25 each, no block)");
19	  it.todo("3 runes yields base premium 60 G (block applies)");
20	  it.todo("4 runes yields base premium 100 G (no block - requires exactly 3)");
21	  it.todo("7 runes yields base premium 175 G (one block of 3 + 4 singles)");
22	
23	  // Alike components
24	  it.todo("2 runes + 1 moonstone yields base premium 75 G (different types, no block)");
25	  it.todo("3 runes + 3 moonstones yields base premium 120 G (two separate blocks)");
26	
27	  // Item-specific modifiers: cursed
28	  it.todo("cursed sword (newcomer) yields 165 G (100 base + 50 curse + 10 first + 5 fee)");
29	
30	  // Item-specific modifiers: high enchantment
31	  it.todo("sword with enchantment exactly 5 (newcomer) triggers high-enchantment surcharge");
32	  it.todo("sword with enchantment 4 (newcomer) does not trigger high-enchantment surcharge");
33	
34	  // Modifier scope on multi-item policies
35	  it.todo("policy with cursed sword and plain amulet: curse surcharge applies only to sword's base premium");
36	
37	  // Policy-wide modifiers: loyalty
38	  it.todo("customer with exactly 2 years receives 20% loyalty discount");
39	
40	  // Policy-wide modifiers: follow-up contract
41	  it.todo("customer's second quote receives 15% follow-up discount");
42	
43	  // Rounding
44	  it.todo("premium calculation yielding 197.5 G rounds up to 198 G (in MHPCO's favor)");
45	
46	  // Integration examples
47	  it.todo("newcomer with cursed sword (steel, enchantment 3) yields 165 G");
48	  it.todo("long-standing customer (3 years) second quote, cursed sword enchantment 7 yields 160 G");
49	});
50	
51	describe("MHPCO Claim Office - claim", () => {
52	  // Standard reimbursement
53	  it.todo("regular sword (steel, enchantment 3), damage 500 G yields payout 400 G");
54	  it.todo("rune damage 200 G yields payout 100 G");
55	
56	  // Deductible per damage event
57	  it.todo("dragon attack damaging sword (500 G) and amulet (300 G) yields payout 600 G");
58	
59	  // High enchantment threshold
60	  it.todo("steel sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible)");
61	
62	  // Dragon material
63	  it.todo("dragon-material sword enchantment 5, damage 800 G yields payout 700 G (full minus deductible)");
64	
65	  // Both clauses: enchantment >= 8 wins (50% rule)
66	  it.todo("dragon-material sword enchantment 9, damage 1000 G yields payout 400 G");
67	  it.todo("dragon-material sword enchantment exactly 8, damage 1000 G yields payout 400 G");
68	
69	  // Cap based on unmodified insurance sum
70	  it.todo("cursed sword has cap 2000 G (based on unmodified insurance value)");
71	  it.todo("sword + 3 runes policy has insurance sum 1750 G (block discount doesn't affect insurance sum)");
72	
73	  // Cap exhaustion across multiple claims
74	  it.todo("sword (cap 2000): first claim 1500 G yields payout 1400 G, remaining cap 600 G");
75	  it.todo("sword (cap 2000) after first 1400 G payout: second claim 1500 G yields payout 600 G, remaining cap 0");
76	
77	  // Multiple items of same type
78	  it.todo("policy with two swords: dragon attack on both treats each as separate damage with own deductible");
79	
80	  // Rounding for payout
81	  it.todo("payout calculation yielding 350.5 G rounds down to 350 G (in MHPCO's favor)");
82	});
83	
84	describe("MHPCO Claim Office - CLI", () => {
85	  it.todo("reads scenario JSON from stdin and writes results JSON to stdout");
86	  it.todo("quote step result contains premium (integer)");
87	  it.todo("claim step result contains payout and remainingCap (integers)");
88	  it.todo("claim references policy by zero-based step index");
89	
90	  // Error cases
91	  it.todo("unknown item type in quote exits non-zero with stderr message and no results on stdout");
92	  it.todo("claim referencing item not in policy exits non-zero with stderr message");
93	  it.todo("claim with negative damage amount exits non-zero with stderr message");
94	  it.todo("claim with more damage entries of a type than policy covers exits non-zero");
95	});
