// claim-office.ts

const PROCESSING_FEE = 5;

export type Customer = {
  yearsInsured: number;
  previousQuotes: number;
};

export type QuoteInput = {
  items: unknown[];
  customer: Customer;
};

export const quote = (_input: QuoteInput): number => {
  return PROCESSING_FEE;
};
